import React from 'react';
import Logo from './Logo.png'; 
import Menu, { Lunch } from './Menu'; 

function App() {
  return (
    <div style={{ backgroundColor: '#000', minHeight: '100vh', margin: 0, padding: 0, fontFamily: 'Arial, sans-serif' }}>
      
      {/* 1. PROFESSIONAL NAVBAR (MATCHING YOUR IMAGE) */}
      <nav style={{ 
        display: 'flex', 
        justifyContent: 'space-between', 
        alignItems: 'center', 
        padding: '15px 50px', 
        backgroundColor: '#0a0a0a', // Darker black for the nav bar
        position: 'sticky',
        top: 0,
        zIndex: 1000,
        borderBottom: '1px solid #1a1a1a'
      }}>
        {/* LOGO ON THE LEFT */}
        <div style={{ display: 'flex', alignItems: 'center' }}>
          <img src={Logo} alt="Àmí by T" style={{ height: '45px', filter: 'contrast(120%) brightness(110%)' }} />
        </div>

        {/* NAVIGATION LINKS IN THE MIDDLE */}
        <div style={{ display: 'flex', gap: '30px' }}>
          {['Home', 'Small Chops', 'Office Lunch', 'About Us'].map((item) => (
            <a key={item} href={`#${item.toLowerCase().replace(' ', '')}`} style={{ 
              color: '#fff', 
              textDecoration: 'none', 
              fontSize: '0.9rem', 
              fontWeight: '500',
              opacity: 0.8
            }}>
              {item}
            </a>
          ))}
        </div>

        {/* CART/BUTTON ON THE RIGHT */}
        <div style={{ 
          backgroundColor: '#D4AF37', 
          color: '#000', 
          padding: '8px 18px', 
          borderRadius: '20px', 
          fontSize: '0.8rem', 
          fontWeight: 'bold',
          cursor: 'pointer'
        }}>
          0 items
        </div>
      </nav>

      {/* 2. THE MAIN CONTENT */}
      <main style={{ padding: '20px 0' }}>
        <div style={{ textAlign: 'center', padding: '60px 20px' }}>
           <h1 style={{ color: '#fff', fontSize: '2.5rem', marginBottom: '10px' }}>Featured Collections</h1>
           <p style={{ color: '#666' }}>Taste and Style curated for you</p>
        </div>

        <Menu />
        
        <hr style={{ border: '0.5px solid #1A1A1A', width: '80%', margin: '40px auto' }} />
        
        <Lunch />
      </main>

      {/* 3. FOOTER */}
      <footer style={{ textAlign: 'center', padding: '60px 40px', color: '#444', fontSize: '0.7rem' }}>
        <p>© 2026 ÀMÍ BY T | LAGOS</p>
      </footer>

    </div>
  );
}

export default App;
